mapper.sql:
select p.product_id, p.category_id, c.category_name, c.unit, p.product_name, p.specification, p.supplier,
       p.latest_sale_amount, p.latest_cost_price, p.create_time, p.remark
from (
    select * from biz_product ${ew.getCustomSqlSegment}
) p
left join biz_product_category c on p.category_id = c.category_id
